files.content:
:root {
  color-scheme: light;
  --bg: #f4efe6;
  --panel: #fffdf8;
  --ink: #1e2430;
  --muted: #6e7687;
  --accent: #0f766e;
  --accent-strong: #115e59;
  --border: #d9d1c4;
  --error: #9f1239;
  --shadow: 0 18px 40px rgba(30, 36, 48, 0.12);
  font-family: "Trebuchet MS", "Segoe UI", sans-serif;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-width: 640px;
  min-height: 100vh;
  background:
    radial-gradient(circle at top left, rgba(15, 118, 110, 0.12), transparent 28%),
    linear-gradient(180deg, #f7f2e9 0%, var(--bg) 100%);
  color: var(--ink);
}

button,
input,
textarea {
  font: inherit;
}

button {
  cursor: pointer;
  border: 1px solid var(--border);
  background: white;
  color: var(--ink);
  border-radius: 999px;
  padding: 0.55rem 0.95rem;
}

button:hover {
  border-color: var(--accent);
}

input,
textarea {
  width: 100%;
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 0.8rem 0.95rem;
  background: white;
  color: var(--ink);
}

textarea {
  resize: vertical;
}

a {
  color: var(--accent-strong);
}

#app {
  min-height: 100vh;
}

.shell {
  min-height: 100vh;
  padding: 1.25rem;
}

.shell.locked {
  filter: blur(8px);
  pointer-events: none;
  user-select: none;
}

.topbar {
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  align-items: center;
  margin-bottom: 1rem;
}

.topbar h1,
.panel h2 {
  margin: 0;
}

.subtitle {
  margin: 0.35rem 0 0;
  color: var(--muted);
}

.session-controls {
  display: flex;
  align-items: center;
  gap: 0.8rem;
  flex-wrap: wrap;
}

.toggle {
  display: inline-flex;
  align-items: center;
  gap: 0.45rem;
  color: var(--muted);
}

.toggle input {
  width: auto;
}

.username {
  font-weight: 700;
}

.error-banner {
  margin-bottom: 1rem;
  padding: 0.9rem 1rem;
  border-radius: 18px;
  background: #ffe4eb;
  color: var(--error);
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 1rem;
}

.main-grid {
  display: grid;
  grid-template-columns: 280px 280px 1fr;
  gap: 1rem;
  align-items: start;
}

.panel {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: 24px;
  padding: 1rem;
  box-shadow: var(--shadow);
}

.panel-header {
  display: flex;
  justify-content: space-between;
  gap: 0.75rem;
  align-items: center;
  margin-bottom: 0.85rem;
}

.create-row {
  display: flex;
  gap: 0.6rem;
  margin-bottom: 1rem;
}

.create-row button {
  flex: none;
}

.item-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 0.7rem;
}

.item-list li {
  border: 1px solid var(--border);
  border-radius: 18px;
  padding: 0.75rem;
  background: white;
}

.inline-actions {
  display: flex;
  gap: 0.55rem;
  margin-top: 0.55rem;
}

.name-button {
  display: inline-block;
  font-weight: 700;
}

.selected {
  color: var(--accent-strong);
}

.conversation {
  min-height: 70vh;
  display: flex;
  flex-direction: column;
}

.post-list {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 0.9rem;
  overflow: auto;
  padding-right: 0.35rem;
}

.post-card {
  border-left: 3px solid #d5edea;
  padding: 0.8rem 0 0 0.95rem;
}

.post-children {
  margin-left: 1.25rem;
  margin-top: 0.8rem;
}

.post-meta {
  display: flex;
  gap: 0.8rem;
  align-items: baseline;
  color: var(--muted);
  font-size: 0.95rem;
}

.post-body {
  margin: 0.55rem 0;
  line-height: 1.45;
  word-break: break-word;
}

.post-actions {
  display: flex;
  gap: 0.55rem;
  flex-wrap: wrap;
  margin-bottom: 0.75rem;
}

.reaction-button.active {
  background: #dff7f4;
  border-color: var(--accent);
}

.composer {
  border: 1px solid var(--border);
  border-radius: 20px;
  padding: 0.9rem;
  background: #fffdfa;
  margin-top: 0.7rem;
}

.composer-toolbar,
.composer-actions {
  display: flex;
  gap: 0.55rem;
  flex-wrap: wrap;
  margin-bottom: 0.7rem;
}

.reply-banner {
  margin-bottom: 0.7rem;
  padding: 0.65rem 0.8rem;
  background: #edf8f6;
  border-radius: 14px;
  display: flex;
  justify-content: space-between;
  gap: 0.8rem;
  align-items: center;
}

.insert-button {
  padding: 0.45rem 0.75rem;
}

.modal-layer {
  position: fixed;
  inset: 0;
  display: grid;
  place-items: center;
  background: rgba(34, 39, 46, 0.22);
  backdrop-filter: blur(10px);
}

.modal-layer.hidden {
  display: none;
}

.modal-card {
  width: min(420px, calc(100vw - 2rem));
  background: white;
  border-radius: 28px;
  border: 1px solid var(--border);
  box-shadow: var(--shadow);
  padding: 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 0.8rem;
}

.modal-card h2,
.modal-card p {
  margin: 0;
}

.error-text {
  color: var(--error);
}

import Ajv from "ajv";

declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

type JsonObject = Record<string, unknown>;

type ReactionMap = Record<string, string[]>;

type PostDoc = {
  msg: string;
  parent?: string;
  reactions?: ReactionMap;
  extensions?: JsonObject;
};

type Entry = {
  path: string;
  name: string;
  doc?: unknown;
  meta?: JsonObject;
};

type PostView = {
  path: string;
  doc: PostDoc;
  meta: JsonObject;
};

type AppState = {
  token: string | null;
  username: string;
  workspaces: string[];
  openWorkspace: string | null;
  channels: string[];
  openChannel: string | null;
  posts: PostView[];
  replyParent: string | null;
  replyParentPreview: string;
  loginError: string;
  error: string;
  extensionEnabled: boolean;
};

const ajv = new Ajv({ allErrors: true });

const validateObject = ajv.compile({
  type: "object",
  additionalProperties: true,
});

const validatePost = ajv.compile({
  type: "object",
  required: ["msg"],
  properties: {
    msg: { type: "string" },
    parent: { type: "string" },
    reactions: {
      type: "object",
      patternProperties: {
        "^:[a-z-]+:$": {
          type: "array",
          items: { type: "string" },
        },
      },
      additionalProperties: false,
    },
    extensions: {
      type: "object",
      additionalProperties: true,
    },
  },
  additionalProperties: false,
});

const REACTIONS: Array<{ name: string; emoji: string; label: string }> = [
  { name: ":smile:", emoji: "🙂", label: "smile" },
  { name: ":frown:", emoji: "🙁", label: "frown" },
  { name: ":like:", emoji: "👍", label: "like" },
  { name: ":celebrate:", emoji: "🎉", label: "celebrate" },
];

const state: AppState = {
  token: null,
  username: "",
  workspaces: [],
  openWorkspace: null,
  channels: [],
  openChannel: null,
  posts: [],
  replyParent: null,
  replyParentPreview: "",
  loginError: "",
  error: "",
  extensionEnabled: true,
};

let pollHandle: number | null = null;
let postsRequestId = 0;

const root = document.getElementById("app");

function dbUrl(path = ""): string {
  return `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}${path}`;
}

function authUrl(): string {
  return `${process.env.DATABASE_HOST}${process.env.AUTH_PATH}`;
}

function authHeaders(): Record<string, string> {
  return state.token ? { Authorization: `Bearer ${state.token}` } : {};
}

function escapeHtml(text: string): string {
  const div = document.createElement("div");
  div.textContent = text;
  return div.innerHTML;
}

function pathName(path: string): string {
  const clean = path.endsWith("/") ? path.slice(0, -1) : path;
  const parts = clean.split("/").filter(Boolean);
  return decodeURIComponent(parts[parts.length - 1] ?? clean);
}

function ensureRoot(): HTMLElement {
  if (!root) {
    throw new Error("Missing app root");
  }
  return root;
}

async function apiRequest(
  path: string,
  options: RequestInit = {},
): Promise<Response> {
  const headers = new Headers(options.headers ?? {});
  Object.entries(authHeaders()).forEach(([key, value]) => headers.set(key, value));
  if (!headers.has("Content-Type") && options.body) {
    headers.set("Content-Type", "application/json");
  }
  return fetch(dbUrl(path), { ...options, headers });
}

async function apiJson<T>(path: string, options: RequestInit = {}): Promise<T> {
  const response = await apiRequest(path, options);
  if (!response.ok) {
    throw new Error(await readError(response));
  }
  return (await response.json()) as T;
}

async function readError(response: Response): Promise<string> {
  let message = `Request failed (${response.status})`;
  try {
    const body = (await response.json()) as Record<string, unknown>;
    if (typeof body.error === "string") {
      message = body.error;
    } else if (typeof body.message === "string") {
      message = body.message;
    }
  } catch {
    if (response.status === 404) {
      message = "Not found";
    } else if (response.status === 409) {
      message = "Already exists";
    }
  }
  return message;
}

function normalizeEntry(entry: unknown): Entry | null {
  if (typeof entry === "string") {
    return {
      path: entry,
      name: pathName(entry),
    };
  }
  if (!entry || typeof entry !== "object") {
    return null;
  }

  const record = entry as Record<string, unknown>;
  const rawPath =
    (typeof record.path === "string" && record.path) ||
    (typeof record.uri === "string" && record.uri) ||
    (typeof record.name === "string" && record.name) ||
    (typeof record.key === "string" && record.key) ||
    "";

  const doc =
    record.doc ??
    record.value ??
    record.data ??
    record.document ??
    record.body;

  const meta =
    (record.meta as JsonObject | undefined) ??
    (record.metadata as JsonObject | undefined);

  if (!rawPath) {
    return null;
  }

  return {
    path: stripDbPrefix(rawPath),
    name: pathName(rawPath),
    doc,
    meta,
  };
}

function stripDbPrefix(path: string): string {
  return path.startsWith(process.env.DATABASE_PATH)
    ? path.slice(process.env.DATABASE_PATH.length)
    : path;
}

function collectionEntries(body: unknown): Entry[] {
  if (Array.isArray(body)) {
    return body.map(normalizeEntry).filter((entry): entry is Entry => entry !== null);
  }
  if (!body || typeof body !== "object") {
    return [];
  }

  const record = body as Record<string, unknown>;
  const candidate =
    record.docs ??
    record.documents ??
    record.items ??
    record.children ??
    record.entries;

  if (Array.isArray(candidate)) {
    return candidate
      .map(normalizeEntry)
      .filter((entry): entry is Entry => entry !== null);
  }

  if (candidate && typeof candidate === "object") {
    return Object.entries(candidate).map(([name, value]) => {
      const normalized = normalizeEntry(value);
      return normalized ?? { path: name, name: pathName(name) };
    });
  }

  return [];
}

function documentContent(body: unknown): { doc: unknown; meta: JsonObject } | null {
  if (!body || typeof body !== "object") {
    return null;
  }
  const record = body as Record<string, unknown>;
  const doc = record.doc ?? record.data ?? record.value ?? body;
  const meta =
    (record.meta as JsonObject | undefined) ??
    (record.metadata as JsonObject | undefined) ??
    {};

  if (!validateObject(doc)) {
    return null;
  }

  return { doc, meta };
}

function sortByName(values: string[]): string[] {
  return [...values].sort((left, right) => left.localeCompare(right));
}

function getMetaString(meta: JsonObject, keys: string[]): string {
  for (const key of keys) {
    if (typeof meta[key] === "string") {
      return meta[key] as string;
    }
  }
  return "";
}

function getTimestamp(meta: JsonObject): number {
  const raw = getMetaString(meta, [
    "createdAt",
    "creationTime",
    "lastModifiedAt",
    "lastUpdatedAt",
  ]);
  const value = Date.parse(raw);
  return Number.isNaN(value) ? 0 : value;
}

function postAuthor(post: PostView): string {
  return (
    getMetaString(post.meta, [
      "createdBy",
      "author",
      "owner",
      "lastModifiedBy",
      "lastUpdatedBy",
    ]) || "unknown"
  );
}

function postTime(post: PostView): string {
  const raw = getMetaString(post.meta, [
    "createdAt",
    "creationTime",
    "lastModifiedAt",
    "lastUpdatedAt",
  ]);
  if (!raw) {
    return "";
  }
  const date = new Date(raw);
  return Number.isNaN(date.valueOf()) ? raw : date.toLocaleString();
}

function renderReactionLabel(name: string): string {
  return REACTIONS.find((reaction) => reaction.name === name)?.emoji ?? name;
}

function formatMessage(message: string): string {
  let html = escapeHtml(message);
  html = html.replace(
    /\[([^\]]+)\]\((https?:\/\/[^\s)]+)\)/g,
    '<a href="$2" target="_blank" rel="noreferrer">$1</a>',
  );
  html = html.replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>");
  html = html.replace(/\*([^*]+)\*/g, "<em>$1</em>");
  for (const reaction of REACTIONS) {
    html = html.replaceAll(reaction.name, reaction.emoji);
  }
  html = html.replace(/\n/g, "<br>");
  return html;
}

async function fetchCollection(path: string): Promise<Entry[]> {
  const body = await apiJson<unknown>(path);
  return collectionEntries(body);
}

async function fetchDocument(path: string): Promise<{ doc: unknown; meta: JsonObject } | null> {
  const body = await apiJson<unknown>(path);
  return documentContent(body);
}

async function loadWorkspaces(): Promise<void> {
  const entries = await fetchCollection("");
  state.workspaces = sortByName(entries.map((entry) => entry.name));
}

async function loadChannels(workspace: string): Promise<void> {
  const entries = await fetchCollection(
    `${encodeURIComponent(workspace)}/channels/`,
  );
  state.channels = sortByName(entries.map((entry) => entry.name));
}

async function loadPosts(workspace: string, channel: string): Promise<void> {
  const requestId = ++postsRequestId;
  const entries = await fetchCollection(
    `${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`,
  );

  const posts = await Promise.all(
    entries.map(async (entry) => {
      if (validatePost(entry.doc)) {
        return {
          path: entry.path,
          doc: entry.doc as PostDoc,
          meta: entry.meta ?? {},
        };
      }

      const loaded = await fetchDocument(entry.path);
      if (!loaded || !validatePost(loaded.doc)) {
        return null;
      }

      return {
        path: entry.path,
        doc: loaded.doc as PostDoc,
        meta: loaded.meta,
      };
    }),
  );

  if (requestId !== postsRequestId) {
    return;
  }

  state.posts = posts
    .filter((post): post is PostView => post !== null)
    .sort((left, right) => getTimestamp(left.meta) - getTimestamp(right.meta));
}

function clearError(): void {
  state.error = "";
  render();
}

function showError(message: string): void {
  state.error = message;
  render();
}

function stopPolling(): void {
  if (pollHandle !== null) {
    window.clearInterval(pollHandle);
    pollHandle = null;
  }
}

function startPolling(): void {
  stopPolling();
  if (!state.openWorkspace || !state.openChannel || !state.token) {
    return;
  }
  pollHandle = window.setInterval(async () => {
    if (!state.openWorkspace || !state.openChannel || !state.token) {
      return;
    }
    try {
      await loadPosts(state.openWorkspace, state.openChannel);
      render();
    } catch {
      // Keep the current view stable during background refresh failures.
    }
  }, 1500);
}

async function login(username: string): Promise<void> {
  state.loginError = "";
  const response = await fetch(authUrl(), {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ username }),
  });
  if (!response.ok) {
    throw new Error(await readError(response));
  }
  const body = (await response.json()) as Record<string, unknown>;
  if (typeof body.token !== "string" || !body.token) {
    throw new Error("Missing token");
  }
  state.token = body.token;
  state.username = username;
  await loadWorkspaces();
}

async function logout(): Promise<void> {
  const headers = authHeaders();
  const response = await fetch(authUrl(), {
    method: "DELETE",
    headers,
  });
  if (!response.ok && response.status !== 204) {
    throw new Error(await readError(response));
  }

  state.token = null;
  state.username = "";
  state.workspaces = [];
  state.openWorkspace = null;
  state.channels = [];
  state.openChannel = null;
  state.posts = [];
  state.replyParent = null;
  state.replyParentPreview = "";
  state.error = "";
  state.loginError = "";
  stopPolling();
}

async function createWorkspace(name: string): Promise<void> {
  const trimmed = name.trim();
  if (!trimmed) {
    throw new Error("Workspace name is required");
  }
  const putWorkspace = await apiRequest(encodeURIComponent(trimmed), {
    method: "PUT",
    body: JSON.stringify({}),
  });
  if (!putWorkspace.ok) {
    throw new Error(await readError(putWorkspace));
  }

  const putChannels = await apiRequest(`${encodeURIComponent(trimmed)}/channels/`, {
    method: "PUT",
  });
  if (!putChannels.ok && putChannels.status !== 412 && putChannels.status !== 409) {
    throw new Error(await readError(putChannels));
  }

  await loadWorkspaces();
  await openWorkspace(trimmed);
}

async function deleteWorkspace(name: string): Promise<void> {
  const response = await apiRequest(encodeURIComponent(name), { method: "DELETE" });
  if (!response.ok && response.status !== 204) {
    throw new Error(await readError(response));
  }

  state.openWorkspace = null;
  state.channels = [];
  state.openChannel = null;
  state.posts = [];
  state.replyParent = null;
  state.replyParentPreview = "";
  stopPolling();
  await loadWorkspaces();
}

async function openWorkspace(name: string): Promise<void> {
  await loadChannels(name);
  state.openWorkspace = name;
  state.openChannel = null;
  state.posts = [];
  state.replyParent = null;
  state.replyParentPreview = "";
  stopPolling();
}

async function createChannel(name: string): Promise<void> {
  if (!state.openWorkspace) {
    throw new Error("Open a workspace first");
  }
  const trimmed = name.trim();
  if (!trimmed) {
    throw new Error("Channel name is required");
  }

  const basePath = `${encodeURIComponent(state.openWorkspace)}/channels/${encodeURIComponent(trimmed)}`;
  const putChannel = await apiRequest(basePath, {
    method: "PUT",
    body: JSON.stringify(state.extensionEnabled ? { gpt54: { topic: trimmed } } : {}),
  });
  if (!putChannel.ok) {
    throw new Error(await readError(putChannel));
  }

  const putPosts = await apiRequest(`${basePath}/posts/`, { method: "PUT" });
  if (!putPosts.ok && putPosts.status !== 412 && putPosts.status !== 409) {
    throw new Error(await readError(putPosts));
  }

  await loadChannels(state.openWorkspace);
  await openChannel(trimmed);
}

async function deleteChannel(name: string): Promise<void> {
  if (!state.openWorkspace) {
    throw new Error("Open a workspace first");
  }
  const response = await apiRequest(
    `${encodeURIComponent(state.openWorkspace)}/channels/${encodeURIComponent(name)}`,
    { method: "DELETE" },
  );
  if (!response.ok && response.status !== 204) {
    throw new Error(await readError(response));
  }

  state.openChannel = null;
  state.posts = [];
  state.replyParent = null;
  state.replyParentPreview = "";
  stopPolling();
  await loadChannels(state.openWorkspace);
}

async function openChannel(name: string): Promise<void> {
  if (!state.openWorkspace) {
    throw new Error("Open a workspace first");
  }
  await loadPosts(state.openWorkspace, name);
  state.openChannel = name;
  state.replyParent = null;
  state.replyParentPreview = "";
  startPolling();
}

async function createPost(message: string): Promise<void> {
  if (!state.openWorkspace || !state.openChannel) {
    throw new Error("Open a channel first");
  }

  const trimmed = message.trim();
  if (!trimmed) {
    throw new Error("Post text is required");
  }

  const response = await apiRequest(
    `${encodeURIComponent(state.openWorkspace)}/channels/${encodeURIComponent(state.openChannel)}/posts/`,
    {
      method: "POST",
      body: JSON.stringify({
        msg: message,
        parent: state.replyParent ?? "",
      }),
    },
  );
  if (!response.ok) {
    throw new Error(await readError(response));
  }

  state.replyParent = null;
  state.replyParentPreview = "";
  await loadPosts(state.openWorkspace, state.openChannel);
}

async function toggleReaction(post: PostView, reactionName: string): Promise<void> {
  const current = structuredClone(post.doc.reactions ?? {}) as ReactionMap;
  const users = new Set(current[reactionName] ?? []);
  if (users.has(state.username)) {
    users.delete(state.username);
  } else {
    users.add(state.username);
  }
  current[reactionName] = [...users];

  const response = await apiRequest(post.path, {
    method: "PATCH",
    body: JSON.stringify([
      {
        op: "ObjectAdd",
        path: "/reactions",
        value: current,
      },
    ]),
  });

  if (!response.ok) {
    throw new Error(await readError(response));
  }

  if (state.openWorkspace && state.openChannel) {
    await loadPosts(state.openWorkspace, state.openChannel);
  }
}

function composeMarkup(parentPath: string | null): string {
  const reactionButtons = REACTIONS.map(
    (reaction) =>
      `<button type="button" class="insert-button" data-insert="${reaction.name}">${reaction.emoji}</button>`,
  ).join("");

  return `
    <section class="composer" data-testid="composer">
      <div class="composer-toolbar">
        <button type="button" class="insert-button" data-wrap="italic" aria-label="insert italic">Italic</button>
        <button type="button" class="insert-button" data-wrap="bold" aria-label="insert bold">Bold</button>
        <button type="button" class="insert-button" data-wrap="link" aria-label="insert link">Link</button>
        ${reactionButtons}
      </div>
      ${
        parentPath
          ? `<div class="reply-banner">Replying to: ${escapeHtml(state.replyParentPreview)} <button type="button" data-action="cancel-reply">Close</button></div>`
          : ""
      }
      <textarea id="post-input" data-testid="post-input" rows="4" placeholder="Write a message"></textarea>
      <div class="composer-actions">
        <button type="button" data-action="submit-post">Post</button>
      </div>
    </section>
  `;
}

function renderPostTree(parent: string, children: Map<string, PostView[]>): string {
  const posts = children.get(parent) ?? [];
  return posts
    .map((post) => {
      const reactions = REACTIONS.map((reaction) => {
        const count = post.doc.reactions?.[reaction.name]?.length ?? 0;
        const active = post.doc.reactions?.[reaction.name]?.includes(state.username);
        return `
          <button
            type="button"
            class="reaction-button ${active ? "active" : ""}"
            data-action="react"
            data-path="${escapeHtml(post.path)}"
            data-reaction="${reaction.name}"
            aria-label="${reaction.label}"
          >${reaction.emoji} <span>${count}</span></button>
        `;
      }).join("");

      const replyComposer =
        state.replyParent === post.path ? composeMarkup(post.path) : "";

      return `
        <article class="post-card" data-testid="post" data-post-path="${escapeHtml(post.path)}">
          <header class="post-meta">
            <strong>${escapeHtml(postAuthor(post))}</strong>
            <span>${escapeHtml(postTime(post))}</span>
          </header>
          <div class="post-body">${formatMessage(post.doc.msg)}</div>
          <div class="post-actions">
            <button type="button" data-action="reply" data-path="${escapeHtml(post.path)}">Reply</button>
            ${reactions}
          </div>
          ${replyComposer}
          <div class="post-children">
            ${renderPostTree(post.path, children)}
          </div>
        </article>
      `;
    })
    .join("");
}

function buildPostMarkup(): string {
  const children = new Map<string, PostView[]>();
  for (const post of state.posts) {
    const parent = post.doc.parent && post.doc.parent !== "" ? post.doc.parent : "";
    const list = children.get(parent) ?? [];
    list.push(post);
    children.set(parent, list);
  }

  return renderPostTree("", children);
}

