function setComposerValue(value: string): void {
  const textarea = document.getElementById("post-input") as HTMLTextAreaElement | null;
  if (textarea) {
    textarea.value = value;
    textarea.focus();
    textarea.selectionStart = textarea.selectionEnd = textarea.value.length;
  }
}

function currentComposerValue(): string {
  const textarea = document.getElementById("post-input") as HTMLTextAreaElement | null;
  return textarea?.value ?? "";
}

function wrapComposer(kind: "italic" | "bold" | "link"): void {
  const textarea = document.getElementById("post-input") as HTMLTextAreaElement | null;
  if (!textarea) {
    return;
  }
  const start = textarea.selectionStart;
  const end = textarea.selectionEnd;
  const selected = textarea.value.slice(start, end);
  let replacement = selected;
  if (kind === "italic") {
    replacement = `*${selected}*`;
  } else if (kind === "bold") {
    replacement = `**${selected}**`;
  } else {
    replacement = `[${selected}](https://)`;
  }
  textarea.setRangeText(replacement, start, end, "end");
  textarea.focus();
}

function bindEvents(): void {
  const app = ensureRoot();

  const loginButton = app.querySelector('[data-action="login"]');
  loginButton?.addEventListener("click", async () => {
    const input = document.getElementById("login-username") as HTMLInputElement | null;
    const username = input?.value.trim() ?? "";
    if (!username) {
      state.loginError = "Username is required";
      render();
      return;
    }
    try {
      await login(username);
      render();
    } catch (error) {
      state.loginError = error instanceof Error ? error.message : "Login failed";
      render();
    }
  });

  const loginInput = document.getElementById("login-username") as HTMLInputElement | null;
  loginInput?.addEventListener("keydown", async (event) => {
    if (event.key === "Enter") {
      event.preventDefault();
      (loginButton as HTMLButtonElement | null)?.click();
    }
  });

  app.querySelector('[data-action="logout"]')?.addEventListener("click", async () => {
    try {
      await logout();
      render();
    } catch (error) {
      showError(error instanceof Error ? error.message : "Logout failed");
    }
  });

  app.querySelector('[data-action="dismiss-error"]')?.addEventListener("click", clearError);

  app.querySelector('[data-action="refresh-workspaces"]')?.addEventListener("click", async () => {
    try {
      await loadWorkspaces();
      render();
    } catch (error) {
      showError(error instanceof Error ? error.message : "Could not load workspaces");
    }
  });

  app.querySelector('[data-action="create-workspace"]')?.addEventListener("click", async () => {
    const input = document.getElementById("workspace-name") as HTMLInputElement | null;
    try {
      await createWorkspace(input?.value ?? "");
      render();
    } catch (error) {
      showError(error instanceof Error ? error.message : "Could not create workspace");
    }
  });

  app.querySelectorAll('[data-action="open-workspace"]').forEach((button) => {
    button.addEventListener("click", async () => {
      try {
        await openWorkspace((button as HTMLElement).dataset.name ?? "");
        render();
      } catch (error) {
        showError(error instanceof Error ? error.message : "Could not open workspace");
      }
    });
  });

  app.querySelector('[data-action="open-workspace-target"]')?.addEventListener("click", async () => {
    const input = document.getElementById("workspace-target") as HTMLInputElement | null;
    try {
      await openWorkspace(input?.value.trim() ?? "");
      render();
    } catch (error) {
      showError(error instanceof Error ? error.message : "Could not open workspace");
    }
  });

  app.querySelectorAll('[data-action="delete-workspace"]').forEach((button) => {
    button.addEventListener("click", async () => {
      try {
        await deleteWorkspace((button as HTMLElement).dataset.name ?? "");
        render();
      } catch (error) {
        showError(error instanceof Error ? error.message : "Could not delete workspace");
      }
    });
  });

  app.querySelector('[data-action="delete-workspace-target"]')?.addEventListener("click", async () => {
    const input = document.getElementById("workspace-target") as HTMLInputElement | null;
    try {
      await deleteWorkspace(input?.value.trim() ?? "");
      render();
    } catch (error) {
      showError(error instanceof Error ? error.message : "Could not delete workspace");
    }
  });

  app.querySelector('[data-action="refresh-channels"]')?.addEventListener("click", async () => {
    if (!state.openWorkspace) {
      return;
    }
    try {
      await loadChannels(state.openWorkspace);
      render();
    } catch (error) {
      showError(error instanceof Error ? error.message : "Could not load channels");
    }
  });

  app.querySelector('[data-action="create-channel"]')?.addEventListener("click", async () => {
    const input = document.getElementById("channel-name") as HTMLInputElement | null;
    try {
      await createChannel(input?.value ?? "");
      render();
    } catch (error) {
      showError(error instanceof Error ? error.message : "Could not create channel");
    }
  });

  app.querySelectorAll('[data-action="open-channel"]').forEach((button) => {
    button.addEventListener("click", async () => {
      try {
        await openChannel((button as HTMLElement).dataset.name ?? "");
        render();
      } catch (error) {
        showError(error instanceof Error ? error.message : "Could not open channel");
      }
    });
  });

  app.querySelector('[data-action="open-channel-target"]')?.addEventListener("click", async () => {
    const input = document.getElementById("channel-target") as HTMLInputElement | null;
    try {
      await openChannel(input?.value.trim() ?? "");
      render();
    } catch (error) {
      showError(error instanceof Error ? error.message : "Could not open channel");
    }
  });

  app.querySelectorAll('[data-action="delete-channel"]').forEach((button) => {
    button.addEventListener("click", async () => {
      try {
        await deleteChannel((button as HTMLElement).dataset.name ?? "");
        render();
      } catch (error) {
        showError(error instanceof Error ? error.message : "Could not delete channel");
      }
    });
  });

  app.querySelector('[data-action="delete-channel-target"]')?.addEventListener("click", async () => {
    const input = document.getElementById("channel-target") as HTMLInputElement | null;
    try {
      await deleteChannel(input?.value.trim() ?? "");
      render();
    } catch (error) {
      showError(error instanceof Error ? error.message : "Could not delete channel");
    }
  });

  app.querySelectorAll('[data-action="reply"]').forEach((button) => {
    button.addEventListener("click", () => {
      const path = (button as HTMLElement).dataset.path ?? "";
      const post = state.posts.find((candidate) => candidate.path === path);
      state.replyParent = path;
      state.replyParentPreview = post?.doc.msg ?? path;
      render();
    });
  });

  app.querySelector('[data-action="cancel-reply"]')?.addEventListener("click", () => {
    state.replyParent = null;
    state.replyParentPreview = "";
    render();
  });

  app.querySelector('[data-action="submit-post"]')?.addEventListener("click", async () => {
    try {
      await createPost(currentComposerValue());
      render();
    } catch (error) {
      showError(error instanceof Error ? error.message : "Could not create post");
    }
  });

  const textarea = document.getElementById("post-input") as HTMLTextAreaElement | null;
  textarea?.addEventListener("keydown", async (event) => {
    if (event.key === "Enter" && !event.shiftKey) {
      event.preventDefault();
      const button = app.querySelector('[data-action="submit-post"]') as HTMLButtonElement | null;
      button?.click();
    }
  });

  app.querySelectorAll("[data-insert]").forEach((button) => {
    button.addEventListener("click", () => {
      setComposerValue(`${currentComposerValue()}${(button as HTMLElement).dataset.insert ?? ""}`);
    });
  });

  app.querySelectorAll("[data-wrap]").forEach((button) => {
    button.addEventListener("click", () => {
      wrapComposer(((button as HTMLElement).dataset.wrap ?? "italic") as "italic" | "bold" | "link");
    });
  });

  app.querySelectorAll('[data-action="react"]').forEach((button) => {
    button.addEventListener("click", async () => {
      const element = button as HTMLElement;
      const post = state.posts.find((candidate) => candidate.path === (element.dataset.path ?? ""));
      if (!post) {
        return;
      }
      try {
        await toggleReaction(post, element.dataset.reaction ?? "");
        render();
      } catch (error) {
        showError(error instanceof Error ? error.message : "Could not update reaction");
      }
    });
  });

  const extensionToggle = document.getElementById("extension-toggle") as HTMLInputElement | null;
  extensionToggle?.addEventListener("change", () => {
    state.extensionEnabled = extensionToggle.checked;
  });
}

function render(): void {
  ensureRoot().innerHTML = appMarkup();
  bindEvents();
}

function main(): void {
  render();
}

document.addEventListener("DOMContentLoaded", () => {
  main();
});

