+
+.conversation {
+  min-height: 70vh;
+  display: flex;
+  flex-direction: column;
+}
+
+.post-list {
+  flex: 1;
+  display: flex;
+  flex-direction: column;
+  gap: 0.9rem;
+  overflow: auto;
+  padding-right: 0.35rem;
+}
+
+.post-card {
+  border-left: 3px solid #d5edea;
+  padding: 0.8rem 0 0 0.95rem;
+}
+
+.post-children {
+  margin-left: 1.25rem;
+  margin-top: 0.8rem;
+}
+
+.post-meta {
+  display: flex;
+  gap: 0.8rem;
+  align-items: baseline;
+  color: var(--muted);
+  font-size: 0.95rem;
+}
+
+.post-body {
+  margin: 0.55rem 0;
+  line-height: 1.45;
+  word-break: break-word;
+}
+
+.post-actions {
+  display: flex;
+  gap: 0.55rem;
+  flex-wrap: wrap;
+  margin-bottom: 0.75rem;
+}
+
+.reaction-button.active {
+  background: #dff7f4;
+  border-color: var(--accent);
+}
+
+.composer {
+  border: 1px solid var(--border);
+  border-radius: 20px;
+  padding: 0.9rem;
+  background: #fffdfa;
+  margin-top: 0.7rem;
+}
+
+.composer-toolbar,
+.composer-actions {
+  display: flex;
+  gap: 0.55rem;
+  flex-wrap: wrap;
+  margin-bottom: 0.7rem;
+}
+
+.reply-banner {
+  margin-bottom: 0.7rem;
+  padding: 0.65rem 0.8rem;
+  background: #edf8f6;
+  border-radius: 14px;
+  display: flex;
+  justify-content: space-between;
+  gap: 0.8rem;
+  align-items: center;
+}
+
+.insert-button {
+  padding: 0.45rem 0.75rem;
+}
+
+.modal-layer {
+  position: fixed;
+  inset: 0;
+  display: grid;
+  place-items: center;
+  background: rgba(34, 39, 46, 0.22);
