+describe("Agent coverage", () => {
+  const workspace = uniqueName("AgentWS");
+  const channel = uniqueName("AgentCH");
+
+  before(() => {
+    apiLogin("agent_setup_user").then((token) => {
+      apiCreateWorkspace(token, workspace);
+      apiCreateChannel(token, workspace, channel);
+      apiLogout(token);
